#include <iostream>
using namespace std;

int main() {
    int x = 10;

    // Pointer declaration and initialization
    int* ptr = &x;

    // Reference declaration
    int& ref = x;

    cout << "x = " << x << endl;
    cout << "&x (address of x) = " << &x << endl;
    cout << "ptr (stores address) = " << ptr << endl;
    cout << "*ptr (dereference) = " << *ptr << endl;
    cout << "ref (reference to x) = " << ref << endl;

    // Modify through pointer
    *ptr = 20;
    cout << "\nAfter *ptr = 20:" << endl;
    cout << "x = " << x << endl;
    cout << "ref = " << ref << endl;

    // Modify through reference
    ref = 30;
    cout << "\nAfter ref = 30:" << endl;
    cout << "x = " << x << endl;

    return 0;
}

#include <iostream>
using namespace std;

// Pass by value - creates a copy
void passByValue(int num) {
    num = 100;
    cout << "Inside passByValue: num = " << num << endl;
}

// Pass by pointer - receives address
void passByPointer(int* numPtr) {
    *numPtr = 200;
    cout << "Inside passByPointer: *numPtr = " << *numPtr << endl;
}

// Pass by reference - receives alias
void passByReference(int& numRef) {
    numRef = 300;
    cout << "Inside passByReference: numRef = " << numRef << endl;
}

int main() {
    int a = 10, b = 20, c = 30;

    cout << "Initial values: a=" << a << ", b=" << b << ", c=" << c << endl;

    passByValue(a);
    cout << "After passByValue: a = " << a << endl;

    passByPointer(&b);
    cout << "After passByPointer: b = " << b << endl;

    passByReference(c);
    cout << "After passByReference: c = " << c << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Dynamic memory allocation for single variable
    int* dynamicVar = new int(50);
    cout << "Dynamic variable: " << *dynamicVar << endl;

    // Dynamic array allocation
    int size = 5;
    int* arr = new int[size] {10, 20, 30, 40, 50};

    // Array name acts as pointer to first element
    cout << "\nArray elements using pointer arithmetic:" << endl;
    for (int i = 0; i < size; i++) {
        cout << "arr + " << i << " = " << *(arr + i) << endl;
    }

    // Pointer to pointer (2D array simulation)
    int** matrix = new int*[2];
    for (int i = 0; i < 2; i++) {
        matrix[i] = new int[3];
        for (int j = 0; j < 3; j++) {
            matrix[i][j] = (i + 1) * (j + 1);
        }
    }

    cout << "\n2D Matrix (2x3):" << endl;
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 3; j++) {
            cout << matrix[i][j] << " ";
        }
        cout << endl;
    }

    // Const pointer and pointer to const
    int x = 100;
    const int* ptr1 = &x;      // pointer to const - can't modify value
    int* const ptr2 = &x;      // const pointer - can't change address
    const int* const ptr3 = &x; // both const

    // Freeing dynamic memory
    delete dynamicVar;
    delete[] arr;
    for (int i = 0; i < 2; i++) {
        delete[] matrix[i];
    }
    delete[] matrix;

    cout << "\nMemory freed successfully" << endl;

    return 0;
}
